#include <stdio.h>
#include <stdlib.h>

// Define the LoG kernel
int log_kernel[5][5] = {{0, 0, -1, 0, 0},
                        {0, -1, -2, -1, 0},
                        {-1, -2, 16, -2, -1},
                        {0, -1, -2, -1, 0},
                        {0, 0, -1, 0, 0}};

// Apply the LoG kernel to an image
void apply_log(int **img, int width, int height) {
  int i, j, k, l;
  int sum;
  for (i = 2; i < height - 2; i++) {
    for (j = 2; j < width - 2; j++) {
      sum = 0;
      for (k = -2; k <= 2; k++) {
        for (l = -2; l <= 2; l++) {
          sum += img[i+k][j+l] * log_kernel[k+2][l+2];
        }
      }
      img[i][j] = sum;
    }
  }
}

int main() {
  // Load an image
  int width, height;
  int **img = load_image(&width, &height);

  // Apply the LoG kernel
  apply_log(img, width, height);

  // Display the result
  display_image(img, width, height);

  return 0;
}
